INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('applause', '/əˈplɔːz/', '鼓掌、喝彩；称赞(u)', '{"example":"The audience gave loud applause.","example_translation":"观众热烈鼓掌。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('pinch', '/pɪntʃ/', '捏、掐(c, vt)；一撮、少量(c)；困苦(u)；逮捕(vt)；(穿的鞋等)夹痛(v)', '{"example":"She pinched my arm gently.","example_translation":"她轻轻掐了我的胳膊。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('belly', '/ˈbeli/', '腹部；(物体的)圆形或凸起部分(c)；(使)(帆)鼓起(v)', '{"example":"The baby patted its soft belly.","example_translation":"婴儿拍了拍它柔软的腹部。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('stomach', '/ˈstʌmək/', '胃(部)(c)；胃口(n)；忍受(vt)', '{"example":"I feel my stomach ache now","example_translation":"我现在感觉胃痛\n\n例句: The smell kills my stomach\n翻译: 这气味让我倒胃口\n\n例句: I can''''t stomach his lies\n翻译: 我无法忍受他的谎言"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('bowel', '/ˈbaʊəl/', '肠(c, usually pl)；内部最深处(pl, the bowels of sth)', '{"example":"She cleansed her bowels daily.","example_translation":"她每天清洗肠道。\n\n例句: We explored the bowels of the cave.\n翻译: 我们探索了洞穴的内部最深处。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('waist', '/weɪst/', '(人或衣服的)腰、腰部(c)', '{"example":"She measured her waist today.","example_translation":"她今天量了自己的腰围。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('hip', '/hɪp/', '髋、臀部(c)', '{"example":"She hurt her hip yesterday.","example_translation":"她昨天伤到了髋部。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('appendix', '/əˈpendɪks/', '阑尾；(书、文件的)附录；附属物(c)', '{"example":"The doctor removed his appendix.","example_translation":"医生切除了他的阑尾。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('leg', '/leɡ/', '(人、裤子、桌子等的)腿(c)；跑(vi)', '{"example":"She crossed her legs gently.","example_translation":"她轻轻交叉双腿。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('thigh', '/θaɪ/', '大腿；(供食用的禽类的)腿(c)', '{"example":"She rubbed her sore thigh gently.","example_translation":"她轻轻揉了揉酸痛的大腿。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('knee', '/niː/', '膝盖、膝关节；(裤子的)膝部(c)', '{"example":"She hit her knee on the table.","example_translation":"她的膝盖撞到了桌子上。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('heel', '/hiːl/', '(脚、鞋、袜等的)后跟(c)；倾斜(phr v, ~ over)', '{"example":"She repaired her shoe''''s heel.","example_translation":"她修好了她鞋子的后跟。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('remains', '/rɪˈmeɪnz/', '遗体；遗迹；剩余物(如剩饭剩菜)(plural)', '{"example":"The archaeologists found ancient remains.","example_translation":"考古学家发现了古老遗迹。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('skeleton', '/ˈskelɪtn/', '骨架、骨骼；(建筑的)骨架(c)；纲要(c, usually sing)；骨骼的', '{"example":"The old building''''s skeleton remains strong.","example_translation":"这座旧建筑的骨架依然坚固。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('joint', '/dʒɔɪnt/', '关节；接头、接缝、结合处(c)；(用接头等)结合(vt)；共同的、联合的(only before noun)', '{"example":"We wrap the joint with tape.","example_translation":"我们用胶带包裹这个接头。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('skin', '/skɪn/', '皮肤、(动物、果蔬的)皮(n)；剥去…的皮(vt)', '{"example":"She applies cream to her skin.","example_translation":"她往皮肤上涂面霜。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('artery', '/ˈɑːrtəri/', '动脉；(河流、公路等的)干线(c)', '{"example":"A blocked artery causes health risks.","example_translation":"一条堵塞的动脉会带来健康风险。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('vein', '/veɪn/', '静脉；翅脉、叶脉；(木头、石头等的)纹理(c)', '{"example":"The doctor injected medicine into her vein","example_translation":"医生将药物注射进她的静脉"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('nerve', '/nɜːrv/', '神经(c)；神经质(pl)；勇气(u)；鼓足勇气(vt, ~ yourself to do sth)', '{"example":"She felt a nerve twitch in her leg","example_translation":"她感到腿上的一根神经在抽搐\n\n例句: His nerves calmed after the test\n翻译: 考试后他的神经质症状缓解了\n\n例句: He had the nerve to speak up\n翻译: 他有勇气站出来说话\n\n例句: She nerved herself to enter the room\n翻译: 她鼓足勇气走进房间"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('cell', '/sel/', '细胞；电池；单人牢房(c)', '{"example":"A plant cell contains chloroplasts.","example_translation":"植物细胞含有叶绿体。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('attribute', '/əˈtrɪbjuːt/', '(人或物的)属性、特征(c)；把…归因于(vt, ~ sth to sb/sth)', '{"example":"She attributes her success to hard work","example_translation":"她把成功归因于努力工作"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('characteristic', '/ˌkærəktəˈrɪstɪk/', '(人或物的)特征、特色(c, usually pl)；特有的、典型的', '{"example":"Her smile shows her sweet characteristic.","example_translation":"她的微笑展现了她甜美的特征。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('feature', '/ˈfiːtʃər/', '(地方或事物的)特征、特色；特写；故事片(c)；面貌(c, usually pl)；以…为特色(vt, ~ sb/sth)', '{"example":"This city features historic buildings","example_translation":"这座城市以历史建筑为特色"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('trait', '/treɪt/', '(某人性格中的)特性、特点；一点(c)', '{"example":"Her honesty is a valuable trait.","example_translation":"她的诚实是一种宝贵的特性。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('gender', '/ˈdʒendər/', '性(别)(n)', '{"example":"The form asks for your gender.","example_translation":"这张表格询问你的性别。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('sex', '/seks/', '(人、动、植物的)性(别)(u)', '{"example":"The doctor discussed the patient''''s sex.","example_translation":"医生讨论了患者的性别。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('age', '/eɪdʒ/', '年龄(段)(n)；时代、时期(c)', '{"example":"She reached the age of 18 last year.","example_translation":"她去年年满18岁。\n\n---\n\n例句: We live in the digital age now.\n翻译: 我们现在生活在数字时代。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('accent', '/ˈæksent/', '口音(n)；重音(c)；着重点(sing)；强调(vt)', '{"example":"She has a British accent.","example_translation":"她有一口英国口音。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('tone', '/toʊn/', '语气(c)；音调；色调(n)；(活动)基调(u, sing)；给…定调子(vt)', '{"example":"She changed her tone suddenly.","example_translation":"她突然改变了语气。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('voice', '/vɔɪs/', '(说话等的)声音、嗓音(n)；意见(c)；发言权(u, sing)；表达(vt)', '{"example":"She raised her voice in the meeting.","example_translation":"她在会议上提高了嗓门。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('mind', '/maɪnd/', '心、头脑(n)；心思；记忆力(c)；介意(~ doing)；注意、当心(v)', '{"example":"She minds her mind when reading.","example_translation":"她阅读时留意自己的心思。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('soul', '/soʊl/', '灵魂、心灵(c)；精神、精髓(u)', '{"example":"Her soul feels peaceful now.","example_translation":"她的心灵此刻感到平静。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('spirit', '/ˈspɪrɪt/', '精神、心灵(n)；情绪(pl)', '{"example":"Her spirit lifts when friends visit.","example_translation":"朋友来访时她情绪高涨。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('conscience', '/ˈkɑːnʃəns/', '良心；愧疚(n)', '{"example":"He had a clear conscience about the decision.","example_translation":"对这个决定他问心无愧。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('ego', '/ˈiːɡoʊ/', '自我；自负、自自尊心(c)(pl, egos)', '{"example":"He has a fragile ego and needs encouragement.","example_translation":"他自尊心脆弱，需要鼓励。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('beauty', '/ˈbjuːti/', '美、美丽(u)；美人、美好的物(c)', '{"example":"She is known for her beauty and grace.","example_translation":"她以美丽和优雅著称。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('grace', '/ɡreɪs/', '(动作的)优雅、优美；(上帝的)恩典(u)；使(某地或某物)优美(vt)', '{"example":"She moved with grace and elegance.","example_translation":"她举止优雅得体。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('health', '/helθ/', '健康(状况)；医疗保健(u)', '{"example":"Health is more important than wealth.","example_translation":"健康比财富更重要。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('fatigue', '/fəˈtiːɡ/', '疲劳(u)；(使…)疲劳(v)；疲劳的', '{"example":"The long journey left them in a state of fatigue.","example_translation":"长途旅行使他们疲惫不堪。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('hunger', '/ˈhʌŋɡər/', '饿；饥饿感(u)；渴望(sing)；渴望(phr v, ~ for/after sb/sth)', '{"example":"His hunger for knowledge led him to read widely.","example_translation":"他对知识的渴望使他广泛阅读。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('thirst', '/θɜːrst/', '口渴(u, sing)；干渴的状态(u)；渴望(sing, phr v, ~ for/after sth)', '{"example":"His thirst for adventure led him to travel.","example_translation":"他对冒险的渴望促使他去旅行。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('virtue', '/ˈvɜːrtʃuː/', '(某人具有的)美德、德行(c)；优点(n)；贞操(u)', '{"example":"Patience is a virtue.","example_translation":"耐心是一种美德。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('allegiance', '/əˈliːdʒəns/', '(对领袖、宗教等的)效忠、忠诚(n)', '{"example":"He swore allegiance to his country.","example_translation":"他宣誓效忠他的国家。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('charity', '/ˈtʃærəti/', '慈善、宽厚(u)；慈善事业(或团体)(n)', '{"example":"She donated money to charity.","example_translation":"她向慈善机构捐了钱。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('courtesy', '/ˈkɜːrtəsi/', '礼貌；好意(u)；礼貌的语言(或行为)(c)', '{"example":"She showed courtesy by holding the door.","example_translation":"她礼貌地为别人扶住了门。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('dignity', '/ˈdɪɡnəti/', '尊严、端庄；高贵(u)', '{"example":"She handled the situation with dignity.","example_translation":"她体面地处理了那个局面。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('discretion', '/dɪˈskreʃn/', '谨慎、慎重；自行决断权(u)', '{"example":"Use your discretion when sharing information.","example_translation":"分享信息时请自行斟酌。"}');
