INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('effort', '/ˈefərt/', '努力(u)；成就、努力的结果(c)', '{"example":"Success requires effort and dedication.","example_translation":"成功需要努力和奉献。"}');
