INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('humor', '/ˈhjuːmər/', '幽默(感)、诙谐(u)；心情(n)(BrE, humour)', '{"example":"He has a good sense of humor.","example_translation":"他很有幽默感。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('wit', '/wɪt/', '机智、风趣(u, sing)；智力(pl)', '{"example":"It takes wit to solve this puzzle.","example_translation":"解开这个谜题需要智慧。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('restraint', '/rɪˈstreɪnt/', '克制、抑制(u)；约束(措施)(n)', '{"example":"She showed restraint in her response.","example_translation":"她在回应中表现得很克制。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('thrift', '/θrɪft/', '节俭、节约(u)', '{"example":"Thrift is a virtue in difficult times.","example_translation":"节俭在困难时期是一种美德。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('hypocrisy', '/hɪˈpɑːkrəsi/', '伪善、虚伪(n)', '{"example":"His hypocrisy was exposed by his actions.","example_translation":"他的伪善被他的行为暴露了。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('vanity', '/ˈvænəti/', '自负、虚荣(心)(u)', '{"example":"Her vanity prevented her from accepting help.","example_translation":"她的虚荣心使她不愿接受帮助。"}');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('consider', '/kənˈsɪdər/', '仔细考虑（~ n/doing/wh-）；考虑、顾及（v）；认为（vt, ~ that | ~ sb/sth as sth）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('contemplate', '/ˈkɑːntəmpleɪt/', '沉思（v）；注视（vt）；打算（vt, ~ n/doing-/wh）', '');
