INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('study', '/ˈstʌdi/', '学习（u）；（专题）研究；书房（c）；学习；研究（计划、文件、问题）；（为…）尽力（v）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('preview', '/ˈpriːvjuː/', '预习；预先审查（vt. c）；预告；预映、预展（c）', '');
