INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('remember', '/rɪˈmembər/', '记得（做某事，过去的人、事等）；回忆起（v）；（在祈祷时）缅怀（vt）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('forget', '/fərˈɡet/', '忘记（~ n/that/wh- | ~ about sth | ~ to do sth）；忽略、不再想（v）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('envisage', '/ɪnˈvɪzɪdʒ/', '想象、设想（~ n/that/doing）；面对（vt）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('imagine', '/ɪˈmædʒɪn/', '想象、设想（~ n/doing/that/wh-）；认为、料想（v）；猜想（vt, ~ that）', '');
