INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('predict', '/prɪˈdɪkt/', '预测、预言、预报（vt, ~ n/that/wh-）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('guess', '/ɡes/', '猜测、推测（v, ~ n/that/wh- | ~ at. c, ~ at/about sth）；猜中（v）；想、以为（v, ~ that）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('assume', '/əˈsuːm/', '假定、假设；承担、就（职）；假装（…的样子等）（~ a manner of）（vt）', '');
