INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('speculate', '/ˈspekjuleɪt/', '推测（v, ~ that/wh- | ~ on/about sth）；投机、做投机买卖（vi, ~ on/in sth）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('wonder', '/ˈwʌndər/', '琢磨、想知道、对…表示怀疑（v, ~ wh/speech- | ~ about）；奇迹、奇观（c）；惊奇、惊讶（u）；奇妙的', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('calculate', '/ˈkælkjuleɪt/', '计算（~ n/that/wh-）；估计、预测（~ that/wh-）（vt）', '');
INSERT INTO abcd (word, phonetic, translation, detail) VALUES ('compute', '/kəmˈpjuːt/', '计算、估算（结果、答案、总数等）（v）', '');
